            aOrbiterE = RotL64((aOrbiterE * 0xAD0D29E34671DCFBULL), 39U);
            //
            aIngress = aOrbiterI ^ RotL64(aOrbiterD, 51U);
            aIngress = aIngress + (RotL64(aOrbiterF, 60U) ^ aOrbiterJ);
            aIngress = aIngress + (RotL64(aOrbiterC, 11U) ^ aOrbiterB);
            aIngress = aIngress + (aOrbiterE ^ RotL64(aOrbiterH, 57U));
