            aWandererG = aWandererG + (((RotL64(aPrevious, 52U) + RotL64(aOrbiterI, 36U)) + aOrbiterB) + RotL64(aCarry, 43U));
            aWandererB = aWandererB ^ ((RotL64(aScatter, 35U) + aOrbiterH) + RotL64(aOrbiterF, 3U));
            aWandererC = aWandererC + ((RotL64(aCross, 5U) + RotL64(aOrbiterI, 57U)) + aOrbiterC);
            aWandererE = aWandererE ^ ((RotL64(aPrevious, 47U) + RotL64(aOrbiterE, 13U)) + aOrbiterF);
            aWandererH = aWandererH + ((((RotL64(aIngress, 11U) + RotL64(aOrbiterJ, 18U)) + aOrbiterB) + RotL64(aCarry, 53U)) + aPhaseBWandererUpdateSaltC[(((31U - aIndex) + 13U)) & S_SALT1]);
            aWandererD = aWandererD ^ (((RotL64(aCross, 58U) + RotL64(aOrbiterE, 51U)) + aOrbiterD) + aPhaseBWandererUpdateSaltB[((aIndex + 14U)) & S_SALT1]);
            //
            aCarry = aCarry + (RotL64(aWandererD, 53U) ^ aWandererB);
