            aOrbiterC = (aOrbiterC + aOrbiterJ) + 0x878E9E26F9743785ULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterC) ^ 0xA621DFAC36737F44ULL;
            aOrbiterF = RotL64((aOrbiterF * 0xF7F7F424B0A17B6DULL), 47U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterC) + 0x44DD8182F67523D3ULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterI) ^ 0x9F2E138FA4180F4AULL;
            aOrbiterA = RotL64((aOrbiterA * 0x3B16C435F51E918BULL), 37U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterG) + 0xDBF367DD4B0BC825ULL;
            aOrbiterJ = ((aOrbiterJ ^ aOrbiterB) ^ 0xD6B9DA9CFECD8E65ULL) ^ aPhaseGOrbiterUpdateSaltA[(((31U - aIndex) + 7U)) & S_SALT1];
            aOrbiterJ = RotL64((aOrbiterJ * 0x4101CC465C1B1F95ULL), 3U);
            //
            aIngress = aOrbiterI ^ RotL64(aOrbiterA, 36U);
            aIngress = aIngress + (RotL64(aOrbiterC, 39U) ^ aOrbiterK);
            aIngress = aIngress + (RotL64(aOrbiterD, 19U) ^ aOrbiterF);
