            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererB = aWandererB + ((((RotL64(aPrevious, 27U) + RotL64(aOrbiterB, 19U)) + aOrbiterH) + RotL64(aCarry, 37U)) + aPhaseGWandererUpdateSaltB[((aIndex + 12U)) & S_SALT1]);
            aWandererI = aWandererI ^ ((RotL64(aIngress, 29U) + RotL64(aOrbiterE, 51U)) + aOrbiterI);
