            aOrbiterK = (((aWandererA + RotL64(aPrevious, 48U)) + RotL64(aCarry, 13U)) + 0x4C84855D0E5BC9B8ULL) + aPhaseHOrbiterAssignSaltB[((aIndex + 26U)) & S_SALT1];
            aOrbiterD = ((aWandererF + RotL64(aIngress, 19U)) + RotL64(aCarry, 43U)) + 0xCBD7033431C11543ULL;
            aOrbiterE = ((aWandererC + RotL64(aCross, 11U)) + RotL64(aCarry, 51U)) + 0xD961130CA2281C83ULL;
