            //
            aOrbiterI = (aOrbiterI + aOrbiterK) + 0xCD8633F1E89B75CAULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterI) ^ 0x42329A9CFB21F6FEULL;
            aOrbiterD = RotL64((aOrbiterD * 0x0A561DC51EC85FCFULL), 5U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterE) + 0xD4E7C884598CE1C0ULL) + aPhaseHOrbiterUpdateSaltE[((aIndex + 18U)) & S_SALT1];
            aOrbiterG = (aOrbiterG ^ aOrbiterK) ^ 0x86E1DD55946F0EFEULL;
            aOrbiterG = RotL64((aOrbiterG * 0x3109D0FABE6DF69FULL), 19U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterA) + 0xA4ACED8AF35D293AULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterC) ^ 0xC41B09ED6F7556B7ULL;
            aOrbiterE = RotL64((aOrbiterE * 0x190C412B97341941ULL), 57U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterB) + 0x34F01973279D5BCFULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterG) ^ 0xF0754BF40434F96BULL;
            aOrbiterA = RotL64((aOrbiterA * 0xB0D2E8EB511765A3ULL), 53U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterF) + 0x6E03E74265205104ULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterA) ^ 0x4D512CA1C56AF082ULL;
            aOrbiterI = RotL64((aOrbiterI * 0x35B6CDD038BC98B5ULL), 43U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterD) + 0x149CB63C74E8FD9DULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterB) ^ 0x56F79276F4B22076ULL;
            aOrbiterF = RotL64((aOrbiterF * 0x74A77DA22C356C09ULL), 23U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterG) + 0xECEDAEAFA2106AA1ULL;
            aOrbiterC = ((aOrbiterC ^ aOrbiterD) ^ 0x3EA34B9287085CF6ULL) ^ aPhaseHOrbiterUpdateSaltA[(((31U - aIndex) + 7U)) & S_SALT1];
            aOrbiterC = RotL64((aOrbiterC * 0x740950A39F2EAA2BULL), 29U);
            //
            aOrbiterE = ((aOrbiterE + aOrbiterI) + 0xE04FE7F4AA4FD566ULL) + aPhaseHOrbiterUpdateSaltB[(((31U - aIndex) + 25U)) & S_SALT1];
            aOrbiterB = (aOrbiterB ^ aOrbiterE) ^ 0x29F9CE939EA3E765ULL;
            aOrbiterB = RotL64((aOrbiterB * 0x9E30F359093B5AEDULL), 11U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterC) + 0xA08EC2DEE5FA5210ULL;
            aOrbiterK = ((aOrbiterK ^ aOrbiterF) ^ 0x243AD10B41E048DDULL) ^ aPhaseHOrbiterUpdateSaltF[((aIndex + 10U)) & S_SALT1];
